// blocks/text/TextBlock.schema.tsx
import {Config, Field} from 'alinea'

export const TextBlock = Config.type('Text block', {
  fields: {
    body: Field.richText('Text')
  }
})

// blocks/text/TextBlock.tsx
import {Infer} from 'alinea'
import {RichText} from 'alinea/ui'
import {TextBlock} from './TextBlock.schema'

type TextBlockData = Infer<typeof TextBlock>

export function TextBlockView({block}: {block: TextBlockData}) {
  return <RichText doc={block.body} />
}

// blocks/image/ImageBlock.schema.tsx
import {Config, Field} from 'alinea'

export const ImageBlock = Config.type('Image block', {
  fields: {
    image: Field.image('Image', {required: true}),
    alt: Field.text('Alt text')
  }
})

// blocks/image/ImageBlock.tsx
import {Infer} from 'alinea'
import {ImageBlock} from './ImageBlock.schema'

type ImageBlockData = Infer<typeof ImageBlock>

export function ImageBlockView({block}: {block: ImageBlockData}) {
  return <img src={block.image} alt={block.alt || ''} />
}

// blocks/gallery/GalleryBlock.schema.tsx
import {Config, Field} from 'alinea'

export const GalleryBlock = Config.type('Gallery block', {
  fields: {
    images: Field.image.multiple('Images')
  }
})

// blocks/gallery/GalleryBlock.tsx
import {Infer} from 'alinea'
import {GalleryBlock} from './GalleryBlock.schema'

type GalleryBlockData = Infer<typeof GalleryBlock>

export function GalleryBlockView({block}: {block: GalleryBlockData}) {
  return (
    <ul>
      {block.images.map(image => (
        <li key={image}>
          <img src={image} alt='' />
        </li>
      ))}
    </ul>
  )
}

// entries/landing/LandingPage.schema.tsx (LandingPage update)
import {Config, Field} from 'alinea'

export const LandingPage = Config.document('Landing page', {
  fields: {
    title: Field.text('Title', {required: true}),
    path: Field.path('Path', {readOnly: true, initialValue: ''}),
    blocks: Field.list('Blocks', {
      schema: {
        TextBlock,
        ImageBlock,
        GalleryBlock
      }
    })
  }
})

// entries/landing/LandingPage.tsx
import {Infer} from 'alinea'
import {LandingPage} from './LandingPage.schema'
import {GalleryBlockView} from '@/blocks/gallery/GalleryBlock'
import {ImageBlockView} from '@/blocks/image/ImageBlock'
import {TextBlockView} from '@/blocks/text/TextBlock'

type LandingData = Infer<typeof LandingPage>
type Block = LandingData['blocks'][number]

export function LandingPageView({page}: {page: LandingData}) {
  return (
    <main>
      <h1>{page.title}</h1>
      {page.blocks.map(block => {
        if (block._type === 'TextBlock') return <TextBlockView key={block._id} block={block} />
        if (block._type === 'ImageBlock') return <ImageBlockView key={block._id} block={block} />
        if (block._type === 'GalleryBlock') return <GalleryBlockView key={block._id} block={block} />
        return null
      })}
    </main>
  )
}
